+ (void)shareAppToOthers {
    NSString *urlString = WBSettingManager.sharedManager.ShareURL ?: @"";
    NSURLComponents *components = [NSURLComponents componentsWithString:urlString];
    if (!components) { return; }

    // 取系统当前首选语言，例如: ar-SA / en-US / zh-Hans-CN
    NSString *preferred = [NSLocale preferredLanguages].firstObject ?: @"en";
    NSString *lang = [[preferred componentsSeparatedByString:@"-"] firstObject].lowercaseString;
    if (lang.length == 0) {
        lang = @"en";
    }

    // 追加或覆盖 lang 参数
    NSMutableArray<NSURLQueryItem *> *items = [components.queryItems mutableCopy] ?: [NSMutableArray array];
    NSInteger existingIndex = NSNotFound;
    for (NSInteger i = 0; i < items.count; i++) {
        NSURLQueryItem *item = items[i];
        if ([item.name isEqualToString:@"lang"]) {
            existingIndex = i;
            break;
        }
    }

    NSURLQueryItem *langItem = [NSURLQueryItem queryItemWithName:@"lang" value:lang];
    if (existingIndex != NSNotFound) {
